const items = $input.all();
if (!items || items.length === 0) {
  throw new Error('No data received from Google Sheets. Check the sheet ID, tab name, and permissions.');
}
for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  const keys = Object.keys(row).filter(k => k !== 'row_number');
  const colA = keys[0];
  const colB = keys[1];
  const colC = keys.length > 2 ? keys[2] : null;
  if (colB && row[colB] && row[colB].toString().toLowerCase().trim() === 'pending' && row[colA] && row[colA].toString().trim()) {
    const topic = row[colA].toString();
    const slug = topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').substring(0,60);
    const todayDate = DateTime.now().toFormat('yyyy-MM-dd');
    return [{json:{topic,rowNumber: row.row_number || (i+2),slug,todayDate,colA,colB,colC}}];
  }
}
throw new Error('No pending topics found in the CloudElite Topics sheet.');

const text = $input.first().json.text;
if (!text) throw new Error('No content received from Gemini (English). Check the AI model response.');
let clean = text.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^```(?:md|markdown|mdx)?\n?/, '').replace(/\n?```$/, '');
}
let articleTitle = '';
const tm = clean.match(/^title:\s*"([^"]*)"/m);
if (tm) articleTitle = tm[1];
const t = $('Find First Pending Topic').first().json;
return [{json:{enContent:clean,articleTitle:articleTitle||t.topic,topic:t.topic,slug:t.slug,rowNumber:t.rowNumber,todayDate:t.todayDate,colA:t.colA,colB:t.colB,colC:t.colC}}];

const text = $input.first().json.text;
if (!text) throw new Error('No content received from Gemini (Arabic). Check the AI model response.');
let clean = text.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^```(?:md|markdown|mdx)?\n?/, '').replace(/\n?```$/, '');
}
const en = $('Clean English Output').first().json;
return [{json:{...en,arContent:clean}}];

const data = $('Clean Arabic Output').first().json;
let hasImage = false;
let imageUrl = '';
let coverImagePath = '/images/blog/salesforce-default.jpg';
let photographerName = '';
let photoUrl = '';
try {
  const r = $input.first().json;
  if (r && r.results && Array.isArray(r.results) && r.results.length > 0) {
    const f = r.results[0];
    if (f.urls && f.urls.regular) {
      imageUrl = f.urls.regular;
      coverImagePath = '/images/blog/' + data.slug + '.jpg';
      hasImage = true;
      photographerName = (f.user && f.user.name) ? f.user.name : '';
      photoUrl = (f.links && f.links.html) ? f.links.html : '';
    }
  }
} catch(e) { hasImage = false; }
const escName = photographerName.replace(/"/g,'\\"');
const credit = photographerName ? ('Photo by ' + escName + ' on Unsplash') : 'PLACEHOLDER';
const creditUrl = photoUrl || 'PLACEHOLDER';
function sub(content) {
  // Normalize markdown: convert * bullets to - for consistent rendering
  content = content.replace(/^(\s*)\*\s+/gm, '$1- ');
  let c = content;
  c = c.replace(/coverImage:\s*"\/images\/blog\/PLACEHOLDER"/, 'coverImage: "' + coverImagePath + '"');
  c = c.replace(/coverImageCredit:\s*"PLACEHOLDER"/, 'coverImageCredit: "' + credit + '"');
  c = c.replace(/coverImageCreditUrl:\s*"PLACEHOLDER"/, 'coverImageCreditUrl: "' + creditUrl + '"');
  return c;
}
const enContent = sub(data.enContent);
const arContent = sub(data.arContent);
return [{json:{...data,enContent,arContent,hasImage,imageUrl,coverImagePath,imageFilePath:'public/images/blog/'+data.slug+'.jpg',photographerName,photoUrl}}];

const t = $('Find First Pending Topic').first().json;
const row = {};
row[t.colA] = t.topic;
row[t.colB] = 'used';
if (t.colC) row[t.colC] = DateTime.now().toFormat('yyyy-MM-dd');
return [{json:{...row,_topic:t.topic}}];
